  "\$schema": "https://docs.renovatebot.com/renovate-schema.json",
  "extends": ["config:recommended"],
  "nix": { "enabled": true },
  "lockFileMaintenance": {
    "enabled": true,
    "schedule": ["before 5am on monday"]
  },
  "packageRules": [{
    "matchManagers": ["nix"],
    "groupName": "nix flake inputs",
    "schedule": ["before 5am on monday"]
  }]
}
```

Convert .tmux.conf to programs.tmux module.

```nix
programs.tmux = {
  enable = true;
  prefix = "C-a";
  terminal = "screen-256color";
  keyMode = "emacs";
  extraConfig = ''
    bind a send-prefix
    bind Z send-keys -R
    bind ^a last-window
    bind k confirm-before -p "kill-window #W? (y/n)" kill-window
    unbind &
    set-window-option -g remain-on-exit on
    bind -T copy-mode ^u send-keys -X page-up
    bind -T copy-mode ^d send-keys -X page-down
    # macOS clipboard integration (reattach-to-user-namespace)
    # Create default session with windows 1-9
  '';
};
```

Convert .gitconfig* files to programs.git module.

```nix
programs.git = {
  enable = true;
  userName = "Clayton O'Neill";
  userEmail = "clayton@oneill.net";
  signing = { key = "clayton@oneill.net"; signByDefault = true; };
  aliases = { lg = "log --oneline --graph --all --decorate --abbrev-commit"; };
  extraConfig = {
    init.defaultBranch = "main";
    branch.autosetuprebase = "always";
    push = { default = "simple"; autoSetupRemote = true; };
    pull.default = "current";
    protocol.version = 2;
    safe.directory = "*";
    hub.protocol = "https";
    github.user = "claytono";
    credential.helper = lib.mkIf pkgs.stdenv.isDarwin "osxkeychain";
    url."git@github.com:claytono".insteadOf = "https://github.com/claytono";
  };
  lfs.enable = true;
  ignores = [ "*.swp" ".vscode" ".DS_Store" ];
};
```

## Goals
1. Add home-manager as flake input
2. Create initial homeConfiguration
3. Move packages to home-manager
4. Set up basic activation

## Steps Completed
- Step 2.1: Update flake.nix with home-manager input
- Step 2.2: Create home.nix with all packages inline
- Step 2.3: Add homeConfigurations output to flake.nix
- Step 2.4: Test activation (nix run home-manager -- switch --flake ~/src/dotfiles)
- Step 2.5: Remove old nix profile (nix profile remove dotfiles)
- Step 2.6: Configure symlink for bare home-manager switch

## Code: flake.nix inputs
```nix
inputs = {
  nixpkgs.url = "github:NixOS/nixpkgs/nixpkgs-unstable";
  home-manager = {
    url = "github:nix-community/home-manager";
    inputs.nixpkgs.follows = "nixpkgs";
  };
};
```

## Code: homeConfigurations
```nix
homeConfigurations."coneill" = home-manager.lib.homeManagerConfiguration {
  pkgs = nixpkgs.legacyPackages.aarch64-darwin;
  modules = [ ./home.nix ];
  extraSpecialArgs = { inherit nix-search-cli strace-macos; };
};
```

## Code: Symlink for bare switch
```nix
home.file.".config/home-manager".source = config.lib.file.mkOutOfStoreSymlink "/Users/coneill/src/dotfiles";
```

